import { Badge } from '@astrojs/starlight/components';
import { getCollection } from 'astro:content';
import ModelCard from '~/components/ai/ModelCard.astro';
import ModelFeatureMatrix from '~/components/ai/ModelFeatureMatrix.astro';

export const allModels = (await getCollection('models')).sort(
  (a, b) => a.data.sortOrder - b.data.sortOrder
);
export const main = allModels.filter((m) => m.data.status === 'main');
export const evaluating = allModels.filter((m) => m.data.status === 'evaluating');

A side-by-side comparison of every active NRP-managed LLM, followed by a card per model with strengths, trade-offs, and recommended uses. Click any model name in the matrix to jump to its card; click the HuggingFace link on any card to open the upstream model page.

